'use server';

export async function sendToN8n(formData: FormData): Promise<void> {
  // Se obtiene la URL desde la variable de entorno local
  const webhookUrl = process.env.NEXT_PUBLIC_N8N_WEBHOOK_URL; 
  
  if (!webhookUrl) {
    console.error("Error: La URL del webhook no está configurada en .env.local");
    return;
  } 
  
  const data = {
    nombre: formData.get('nombre'),
    email: formData.get('email'),
    phone: data.get('phone'),
    rubro: formData.get('rubro'),
    red_social: formData.get('red_social'),
    origen: 'santisoft.cl',
    fecha: new Date().toISOString()
  };

  try {
    await fetch(webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    });
  } catch (e) {
    console.error("Error en el envío:", e);
  }
}
